    header {
      background-color: #333;
      color: white;
      padding: 20px;
    }
    .logo {
      font-weight: bold;
      font-size: 24px;
      float: left;
    }
    nav {
      float: right;
    }
    nav ul {
      list-style: none;
      margin: 0;
      padding: 0;
    }
    nav ul li {
      display: inline-block;
      margin-left: 20px;
    }
    nav ul li a {
      color: white;
      text-decoration: none;
      font-size: 18px;
      transition: all 0.3s ease;
    }
    nav ul li a:hover {
      color: lightgray;
    }
    /* Content Styles */
    .container {
      width: 80%;
      margin: auto;
    }
    .image {
      width: 100%;
      text-align: center;
      margin: 20px 0;
