      list-style: none;
      margin: 0;
      padding: 0;
    }
    .facts ul li {
      margin: 10px 0;
    }
    /* Footer Styles */
    footer {
      background-color: #f2f2f2;
      color: #333;
      text-align: center;
      padding: 20px;
      position: absolute;
      bottom: 0;
      width: 100%;
    }
  </style>
</head>
<body>
  <header>
    <div class="container">
      <div class="logo">Panda Page</div>
      <nav>
        <ul>
          <li><a href="#">Home</a></li>
          <li><a href="#">About</a></li>
          <li><a href="#">Contact</a></li>
        </ul>
      </nav>
    </div>
  </header>
  <div class="image">
    <img src="https://upload.wikimedia.org/wikipedia/commons/thumb/0/0f/Giant_Pandas_in_Beijing_Zoo_1.jpg/1200px-Giant_Pandas_in_Beijing_Zoo_1.jpg" alt="Panda eating bamboo">
  </div>
  <div class="container">
    <h1>What is a Panda?</h1>
    <p class="description">Pandas are bears native to central China that have distinctive black and white coat. They are famous for their unique diet, which almost exclusively consists of bamboo.</p>
    <div class="facts">
      <h2>5 Fun Facts about Pandas:</h2>
      <ul>
        <li>Although they are classified as carnivores, over 99% of their diet is bamboo</li>
        <li>Pandas have been known to eat as much as 50 pounds of bamboo in a single day</li>
        <li>Giant pandas can weigh up to 350 pounds and can reach up to 6 feet in length</li>
        <li>Panda cubs are born blind and helpless, only opening their eyes after approximately six to eight weeks</li>
        <li>The scientific name for the giant panda is Ailuropoda melanoleuca, which means “black and white cat-foot”</li>
      </ul>
    </div>
  </div>
  <footer>
    <div class="container">
      © 2023 Panda Page
    </div>
  </footer>
</body>
</html>
